package com.hospital.management.controller.admission;import com.hospital.management.model.*;import com.hospital.management.service.*;import javax.servlet.*;import javax.servlet.annotation.WebServlet;import javax.servlet.http.*;import java.io.*;@WebServlet("/admin/beds/edit")public class BedEditServlet extends BedCreateServlet{protected void doGet(HttpServletRequest q,HttpServletResponse r)throws ServletException,IOException{Long id=AdmissionRequest.id(q.getParameter("id"));if(id==null){r.sendError(400);return;}Bed x=s.getBed(id).orElse(null);if(x==null){r.sendError(404);return;}BedForm f=new BedForm();f.setBedId(x.getBedId());f.setRoomId(x.getRoomId());f.setBedNumber(x.getBedNumber());f.setStatus(x.getStatus());q.setAttribute("bedForm",f);show(q,r,"EDIT");}protected void doPost(HttpServletRequest q,HttpServletResponse r)throws ServletException,IOException{BedForm f=form(q);ServiceResult<Void>x=s.updateBed(f,AdmissionRequest.audit(q));if(x.isSuccess()){r.sendRedirect(q.getContextPath()+"/admin/beds/view?id="+f.getBedId());return;}q.setAttribute("bedForm",f);q.setAttribute("errors",x.getErrors());q.setAttribute("errorMessage",x.getMessage());show(q,r,"EDIT");}}
